    "./docker-compose.yml": "version: '3.9'

# One-command demo stack: docker compose up --build
# Opens on http://localhost:3000
# Login: tenant=alpha, user=admin-user (pre-set in browser localStorage by the app)

services:
  db:
    image: postgres:16-alpine
    environment:
      POSTGRES_DB: clerkos
      POSTGRES_USER: clerkos
      POSTGRES_PASSWORD: clerkos_demo
    volumes:
      - ./demo/init.sql:/docker-entrypoint-initdb.d/01-init.sql:ro
      - pgdata:/var/lib/postgresql/data
    ports:
      - "5432:5432"
    healthcheck:
      test: ["CMD-SHELL", "pg_isready -U clerkos -d clerkos"]
      interval: 5s
      timeout: 5s
      retries: 12

  app:
    build: .
    ports:
      - "3000:3000"
    environment:
      DATABASE_URL: postgresql://clerkos:clerkos_demo@db:5432/clerkos
      NODE_ENV: development
      PORT: 3000
      OWNER_OPEN_ID: admin-user
      DEFAULT_TENANT_SLUG: alpha
    depends_on:
      db:
        condition: service_healthy
    restart: on-failure

volumes:
  pgdata:
