    "./server/trpc/db.ts": "import { and, eq, sql } from 'drizzle-orm';
import { drizzle } from 'drizzle-orm/postgres-js';
import postgres from 'postgres';
import type { InsertAuditEvent, InsertUser } from '../drizzle/schema';
import {
  auditEvents,
  cases,
  clerkAllocations,
  clerkDiaries,
  documents,
