// ─── Diary ───────────────────────────────────────────────────────────────────

export async function getClerkDiaryByDate(clerkId: number, date: string, tenantId: string) {
  const db = await getDb();
  if (!db) return [];
  return db
    .select()
    .from(clerkDiaries)
    .where(
      and(
        eq(clerkDiaries.clerkId, clerkId),
        eq(clerkDiaries.date, date),
