                                {' '}· Due {new Date(a.dueDate + 'T00:00:00').toLocaleDateString('en-GB', { day: 'numeric', month: 'short' })}
                              </span>
                            )}
                          </p>
                          {a.notes && (
                            <p className="text-xs text-slate-400 dark:text-slate-500 mt-1">{a.notes}</p>
                          )}
                        </div>

                        <div className="flex gap-2 flex-shrink-0">
