import * as trpcExpress from '@trpc/server/adapters/express';
import compression from 'compression';
import cors from 'cors';
import { randomUUID } from 'crypto';
import dotenv from 'dotenv';
import express, { NextFunction, Request, Response } from 'express';
import helmet from 'helmet';
import { rateLimit } from 'express-rate-limit';
import path from 'path';
import Stripe from 'stripe';
import { fileURLToPath } from 'url';
import { z } from 'zod';
import { db } from './db/index';
import { complianceBundles, contacts, deploymentStatus, intakeForms, leads, monitoredCompanies } from './db/schema';
import { companiesHouseService } from './services/companiesHouse';
import { getUserByOpenId, getTenantBySlug, setTenantContext } from './trpc/db';
import { startAnalysis, getAnalysis, listAnalyses } from './services/ultaiAgent';
import { lunarTriage } from './engine/lunar';
import { ultraCoreGate } from './engine/ultracore';
import { buildVaultEvent } from './engine/vaultline-audit';
import { lolaFollowUp } from './engine/lola';
import { intakeMatters, vaultEvents } from './db/schema';
import { getUserFromRequest, getTenantSlugFromRequest } from './trpc/_core/auth';
import { appRouter } from './trpc/routers';
import { desc, eq } from 'drizzle-orm';

// Load environment variables
dotenv.config();

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
const PORT = process.env.PORT || 3000;
const DEPLOY_RECORD_TOKEN = process.env.DEPLOY_RECORD_TOKEN;

// ── Startup env validation ─────────────────────────────────────────────────
const ENV_OPTIONAL = [
  ['STRIPE_SECRET_KEY',           'Stripe payments disabled'],
  ['STRIPE_WEBHOOK_SECRET',       'Stripe webhook disabled'],
  ['STRIPE_PRICE_ID',             'Stripe checkout disabled'],
  ['ANTHROPIC_API_KEY',           'UltAi AI analysis disabled'],
  ['GEMINI_API_KEY',              'Gemini AI disabled'],
  ['COMPANIES_HOUSE_API_KEY',     'Companies House lookup disabled'],
  ['AZURE_SERVICE_BUS_CONNECTION_STRING', 'Service Bus queue disabled'],
  ['DATABASE_URL',                'Running in demo mode (in-memory data)'],
];
for (const [key, note] of ENV_OPTIONAL) {
  if (!process.env[key]) console.warn(`[env] ${key} not set — ${note}`);
}
if (!process.env.DEPLOY_RECORD_TOKEN) {
  console.warn('[env] DEPLOY_RECORD_TOKEN not set — deployment recording endpoint unprotected');
}

// Stripe client – only initialised when key is present
const stripeSecretKey = process.env.STRIPE_SECRET_KEY;
const stripe = stripeSecretKey ? new Stripe(stripeSecretKey, { apiVersion: '2023-10-16' }) : null;

// Wraps async Express handlers so thrown errors propagate to the error middleware.
// Express 4 does not catch rejected promises from async route handlers.
function asyncHandler(
  fn: (req: Request, res: Response, next: NextFunction) => Promise<unknown>,
) {
  return (req: Request, res: Response, next: NextFunction) => {
    fn(req, res, next).catch(next);
  };
}

// ============================================================================
// ZOD VALIDATION SCHEMAS
// ============================================================================

const leadSchema = z.object({
  name: z.string().min(1).max(255).trim(),
  email: z.string().email().max(255).trim(),
  company: z.string().max(255).trim().optional(),
  product: z.enum(['vaultline', 'ultai', 'fineguard']).optional(),
  phone: z.string().max(50).trim().optional(),
  message: z.string().max(2000).trim().optional(),
});

const intakeSchema = z.object({
  clientName: z.string().min(1).max(255).trim(),
  clientEmail: z.string().email().max(255).trim().optional(),
  clientPhone: z.string().max(50).trim().optional(),
  matterType: z.string().min(1).max(100).trim(),
  urgency: z.enum(['low', 'medium', 'high', 'critical']),
  description: z.string().max(5000).trim().optional(),
  claimValue: z.string().max(50).trim().optional(),
});

const contactSchema = z.object({
  name: z.string().min(1).max(255).trim(),
  email: z.string().email().max(255).trim(),
  subject: z.string().max(255).trim().optional(),
  message: z.string().min(1).max(5000).trim(),
});

const lunarIntakeSchema = z.object({
  name: z.string().min(1).max(255).trim(),
  email: z.string().email().max(255).trim(),
  issueType: z.string().min(2).max(100).trim(),
  description: z.string().min(10).max(10000).trim(),
});

// ============================================================================
// STRIPE WEBHOOK  (must be registered BEFORE express.json() to access raw body)
// ============================================================================

/**
 * POST /api/stripe/webhook
 * Receives Stripe events. On checkout.session.completed, marks the company as monitored.
 * Requires raw body — registered before express.json().
 */
app.post(
  '/api/stripe/webhook',
  express.raw({ type: 'application/json' }),
  async (req: Request, res: Response) => {
    if (!stripe) {
      return res.status(500).json({ error: 'Stripe not configured' });
    }

    const sig = req.headers['stripe-signature'] as string;
    const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET;

    if (!webhookSecret) {
      return res.status(500).json({ error: 'Stripe webhook secret not configured' });
    }

    let event: Stripe.Event;
    try {
      event = stripe.webhooks.constructEvent(req.body, sig, webhookSecret);
    } catch (err) {
      console.error('Stripe webhook signature verification failed:', err);
      return res.status(400).json({ error: 'Invalid signature' });
    }

    if (event.type === 'checkout.session.completed') {
      const session = event.data.object as Stripe.Checkout.Session;
      const companyNumber = session.metadata?.companyNumber;
      const companyName = session.metadata?.companyName;

      if (companyNumber && companyName) {
        try {
          await db
            .insert(monitoredCompanies)
            .values({
              companyNumber,
              companyName,
              stripeSessionId: session.id,
            })
            .onConflictDoNothing();

          console.log(`✅ Company monitored: ${companyName} (${companyNumber})`);
        } catch (err) {
          console.error('Error persisting monitored company:', err);
          return res.status(500).json({ error: 'Database error' });
        }
      }
    }

    res.json({ received: true });
  }
);

// ============================================================================
// TRPC API (ClerkOS Core Engine)
// ============================================================================

app.use(
  '/api/trpc',
  trpcExpress.createExpressMiddleware({
    router: appRouter,
    createContext: async ({ req, res }) => {
      // 1. Resolve auth user (Azure AD B2C JWT or dev x-user-open-id header)
      let user = null;
      try {
        const authUser = await getUserFromRequest(req);
        if (authUser) {
          // 2. Resolve tenant slug from subdomain / x-tenant header / env
          const slug = getTenantSlugFromRequest(req);
          const tenant = slug ? await getTenantBySlug(slug) : undefined;
          const tenantId = tenant?.id ?? null;

          // 3. Set RLS session context so PostgreSQL policies fire
          if (tenantId) await setTenantContext(tenantId);

          // 4. Look up the DB user record (creates on first sign-in via upsertUser in auth router)
          const dbUser = await getUserByOpenId(authUser.openId, tenantId ?? undefined);
          if (dbUser) user = dbUser;

          return { user, tenantId: tenantId ?? null, tenant: tenant ?? null, req, res };
        }
      } catch {
        // graceful degradation — return null context on any error
      }
      return { user: null, tenantId: null, tenant: null, req, res };
    },
  }),
);

// Middleware
app.use(helmet({
  contentSecurityPolicy: false,       // managed per-environment in staticwebapp.config.json
  crossOriginEmbedderPolicy: false,
}));
app.use(compression());

const writeLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 30,
  standardHeaders: true,
  legacyHeaders: false,
  message: { ok: false, error: 'Too many requests, please try again later.' },
});

const readLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 200,
  standardHeaders: true,
  legacyHeaders: false,
  message: { ok: false, error: 'Too many requests, please try again later.' },
});

const allowedOrigins = process.env.ALLOWED_ORIGINS
  ? process.env.ALLOWED_ORIGINS.split(',').map((s) => s.trim())
  : ['http://localhost:5173', 'http://localhost:3000'];

app.use(cors({
  origin: (origin, callback) => {
    if (!origin || allowedOrigins.includes(origin)) {
      callback(null, true);
    } else {
      callback(new Error(`CORS: origin ${origin} not allowed`));
    }
  },
  credentials: true,
}));

app.use((_req, res, next) => {
  const start = Date.now();
  res.on('finish', () => res.setHeader('X-Response-Time', `${Date.now() - start}ms`));
  next();
});

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Logging middleware
app.use((req: Request, _res: Response, next: NextFunction) => {
  if (req.path.startsWith('/api') || req.path.startsWith('/trpc')) {
    console.log(`${new Date().toISOString()} ${req.method} ${req.path}`);
  }
  next();
});

// Attach a unique request ID to every request for log correlation
app.use((_req: Request, res: Response, next: NextFunction) => {
  res.setHeader('X-Request-Id', randomUUID());
  next();
});

// ============================================================================
// HEALTH CHECK ENDPOINT
// ============================================================================

/**
 * GET /api/ping
 * Lightweight liveness check — no DB call
 */
app.get('/api/ping', (_req, res) => res.json({ ok: true, ts: Date.now() }));

/**
 * GET /api/health
 * Health check endpoint
 */
app.get('/api/health', asyncHandler(async (req: Request, res: Response) => {
  try {
    // Check database connection
    await db.select().from(deploymentStatus).limit(1);

    res.setHeader('Cache-Control', 'no-cache');
    res.json({
      status: 'ok',
      timestamp: new Date().toISOString(),
      database: 'connected',
    });
  } catch (error) {
    res.status(503).json({
      status: 'unhealthy',
      timestamp: new Date().toISOString(),
      database: 'disconnected',
    });
  }
}));

// ============================================================================
// STRIPE CHECKOUT API ENDPOINTS
// ============================================================================

/**
 * POST /api/stripe/checkout
 * Creates a Stripe Checkout session for FineGuard monitoring activation.
 * Body: { companyNumber: string, companyName: string }
 * Returns: { url: string }
 */
app.post('/api/stripe/checkout', asyncHandler(async (req: Request, res: Response) => {
  if (!stripe) {
    return res.status(500).json({ error: 'Stripe not configured' });
  }

  const { companyNumber, companyName } = req.body;

  if (!companyNumber || !companyName) {
    return res.status(400).json({ error: 'companyNumber and companyName are required' });
  }

  const priceId = process.env.STRIPE_PRICE_ID;
  if (!priceId) {
    return res.status(500).json({ error: 'STRIPE_PRICE_ID not configured' });
  }

  const appUrl = process.env.APP_URL || `http://localhost:${PORT}`;

  try {
    const session = await stripe.checkout.sessions.create({
      mode: 'subscription',
      line_items: [{ price: priceId, quantity: 1 }],
      metadata: { companyNumber, companyName },
      success_url: `${appUrl}/compliance-bundle?activated=1&company=${encodeURIComponent(companyNumber)}`,
      cancel_url: `${appUrl}/compliance-bundle`,
    });

    res.json({ url: session.url });
  } catch (err) {
    console.error('Stripe checkout session error:', err);
    res.status(500).json({ error: 'Failed to create checkout session' });
  }
}));

