const SYSTEM_PROMPT = `You are UltAi, an expert contract intelligence agent with the rigour of a senior commercial solicitor.

Workflow — call all four functions in order:
1. extract_metadata
2. identify_risks
3. extract_obligations
4. complete_analysis

Be thorough. Always complete all four calls.`;

// ── Runner ────────────────────────────────────────────────────────────────────

export async function runGeminiAgent(
  record: AnalysisRecord,
  contractText: string,
): Promise<void> {
  const apiKey = process.env.GEMINI_API_KEY;
  if (!apiKey) {
    record.status = 'failed';
    record.error = 'GEMINI_API_KEY is not set';
    record.completedAt = new Date().toISOString();
    return;
  }

  const genAI = new GoogleGenerativeAI(apiKey);
  const model = genAI.getGenerativeModel({
    model: 'gemini-1.5-flash',
    systemInstruction: SYSTEM_PROMPT,
    tools: [{ functionDeclarations: tools }],
    toolConfig: { functionCallingConfig: { mode: FunctionCallingMode.AUTO } },
  });

  let metadata: AnalysisResult['metadata'] | null = null;
  let riskFlags: AnalysisResult['riskFlags'] = [];
  let obligations: AnalysisResult['obligations'] = [];
  let keyDates: AnalysisResult['keyDates'] = [];
  let score: number | null = null;
  let level: AnalysisResult['riskLevel'] | null = null;
  let summary = '';
  let recommendations: string[] = [];

  try {
    const chat = model.startChat();
    let response = await chat.sendMessage(
      `Analyse this contract and run all four analysis functions in sequence:\n\n---\n${contractText}\n---`,
    );

    const MAX_TURNS = 10;
    let turns = 0;

    while (turns < MAX_TURNS) {
      turns++;
      const parts = response.response.candidates?.[0]?.content?.parts ?? [];
      const funcCalls = parts.filter((p) => p.functionCall);

      if (funcCalls.length === 0) break;

      const funcResults = funcCalls.map((part) => {
        const fc = part.functionCall!;
        const args = fc.args as Record<string, unknown>;
        record.agentLog.push(`[tool:gemini] ${fc.name}`);

        if (fc.name === 'extract_metadata') {
          metadata = args as unknown as AnalysisResult['metadata'];
        } else if (fc.name === 'identify_risks') {
          riskFlags = (args.riskFlags ?? []) as AnalysisResult['riskFlags'];
        } else if (fc.name === 'extract_obligations') {
          obligations = (args.obligations ?? []) as AnalysisResult['obligations'];
          keyDates = (args.keyDates ?? []) as AnalysisResult['keyDates'];
        } else if (fc.name === 'complete_analysis') {
          score = args.riskScore as number;
          level = args.riskLevel as AnalysisResult['riskLevel'];
          summary = args.summary as string;
          recommendations = (args.recommendations ?? []) as string[];
        }

        return {
          functionResponse: {
            name: fc.name,
            response: { result: 'ok' },
          },
        };
      });

      if (score !== null) break;
      response = await chat.sendMessage(funcResults);
    }

    if (score === null || !metadata || !level) {
      throw new Error('Gemini agent did not complete all required analysis steps');
    }

    record.result = { metadata, riskScore: score, riskLevel: level, riskFlags, obligations, keyDates, summary, recommendations };
    record.status = 'complete';
    record.completedAt = new Date().toISOString();
  } catch (err) {
    record.status = 'failed';
    record.error = err instanceof Error ? err.message : String(err);
    record.completedAt = new Date().toISOString();
  }
}

import { ServiceBusClient as AzureServiceBusClient } from '@azure/service-bus';

// ─── Config ───────────────────────────────────────────────────────────────────

const CONNECTION_STRING = process.env.AZURE_SERVICE_BUS_CONNECTION_STRING ?? '';
const NAMESPACE = process.env.AZURE_SERVICE_BUS_NAMESPACE ?? '';

// ─── Lazy client ──────────────────────────────────────────────────────────────

let _client: AzureServiceBusClient | null = null;

function getSBClient(): AzureServiceBusClient | null {
  if (_client) return _client;
  if (CONNECTION_STRING) {
    try {
      _client = new AzureServiceBusClient(CONNECTION_STRING);
      console.log('[ServiceBus] Connected via connection string');
      return _client;
    } catch (err) {
      console.warn('[ServiceBus] Failed to create client:', err);
    }
  }
  return null;
}

// ─── Public API ───────────────────────────────────────────────────────────────

export const ServiceBusClient = {
  /**
   * Send a message to a Service Bus queue.
   * Silently no-ops if Service Bus is not configured (dev/test environments).
   */
  async send(queueName: string, body: Record<string, unknown>): Promise<boolean> {
    const client = getSBClient();
    if (!client) {
      console.debug(`[ServiceBus] Not configured — message to "${queueName}" dropped:`, body);
      return false;
    }

    const sender = client.createSender(queueName);
    try {
      await sender.sendMessages({ body });
      return true;
    } catch (err) {
      console.error(`[ServiceBus] Failed to send to "${queueName}":`, err);
      return false;
    } finally {
      await sender.close();
    }
  },

  /**
   * Register a message handler on a queue.
   * Only activates when Service Bus is configured.
   */
  async subscribe(
    queueName: string,
    handler: (body: unknown) => Promise<void>,
  ): Promise<void> {
    const client = getSBClient();
    if (!client) {
      console.info(`[ServiceBus] Not configured — skipping subscription to "${queueName}"`);
      return;
    }

    const receiver = client.createReceiver(queueName);
    receiver.subscribe({
      processMessage: async (msg) => {
        await handler(msg.body);
        await receiver.completeMessage(msg);
      },
      processError: async (err) => {
        console.error(`[ServiceBus] Error on "${queueName}":`, err);
      },
    });

    console.log(`[ServiceBus] Subscribed to "${queueName}"`);
  },
};

