                    </>
                  ) : (
                    'Book Demo'
                  )}
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>

        <p className="text-center text-gray-500 text-sm mt-6">
          By submitting this form, you agree to our terms of service and privacy policy
        </p>
      </div>
    </div>
  );
}

