  cancelled: 'bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400',
};

function ScheduleDialog({
  open,
  onOpenChange,
  cases,
}: {
  open: boolean;
  onOpenChange: (v: boolean) => void;
  cases: { id: number; referenceNumber: string; title: string }[];
}) {
  const utils = trpc.useContext();
  const create = trpc.hearings.create.useMutation({
    onSuccess: () => {
      utils.hearings.list.invalidate();
      utils.dashboard.stats.invalidate();
      onOpenChange(false);
      toast.success('Hearing scheduled');
    },
    onError: (e) => toast.error(e.message),
  });

  const today = new Date().toISOString().split('T')[0];
  const [form, setForm] = useState({
    caseId: '',
    hearingDate: today,
    hearingTime: '10:00',
    courtroom: '',
    judge: '',
    notes: '',
  });

  const field = (key: keyof typeof form) => ({
    value: form[key],
    onChange: (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) =>
      setForm((f) => ({ ...f, [key]: e.target.value })),
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.caseId) { toast.error('Select a case'); return; }
    create.mutate({
      caseId: Number(form.caseId),
      hearingDate: form.hearingDate,
      hearingTime: form.hearingTime,
      courtroom: form.courtroom,
      judge: form.judge,
      notes: form.notes || undefined,
    });
  };

  const inputClass =
    'w-full px-3 py-2 text-sm border border-slate-200 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-blue-500';

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Schedule Hearing</DialogTitle>
          <DialogDescription>Assign a court date and room to a case.</DialogDescription>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Case *</label>
            <select {...field('caseId')} required className={inputClass}>
              <option value="">— Select case —</option>
              {cases.map((c) => (
                <option key={c.id} value={String(c.id)}>
                  {c.referenceNumber} · {c.title}
                </option>
              ))}
            </select>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Date *</label>
              <input type="date" {...field('hearingDate')} required className={inputClass} />
            </div>
            <div>
              <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Time *</label>
              <input type="time" {...field('hearingTime')} required className={inputClass} />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Courtroom *</label>
              <input {...field('courtroom')} required placeholder="e.g. Court 3" className={inputClass} />
            </div>
            <div>
              <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Judge *</label>
              <input {...field('judge')} required placeholder="Judge surname" className={inputClass} />
            </div>
          </div>
          <div>
            <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Notes</label>
            <textarea {...field('notes')} rows={2} placeholder="Optional notes" className={inputClass} />
          </div>
          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={() => onOpenChange(false)}
              className="px-4 py-2 text-sm rounded-lg border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={create.isLoading}
              className="px-4 py-2 text-sm font-medium rounded-lg bg-blue-600 text-white hover:bg-blue-700 disabled:opacity-50 transition-colors"
            >
              {create.isLoading ? 'Scheduling…' : 'Schedule'}
            </button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

export default function Hearings() {
  const [status, setStatus] = useState<StatusFilter>('all');
  const [showSchedule, setShowSchedule] = useState(false);

  const today = new Date().toISOString().split('T')[0];

  const { data: hearings = [], isLoading, error } = trpc.hearings.list.useQuery(
    status === 'all' ? undefined : { status },
    { retry: false },
  );
  const { data: cases = [] } = trpc.cases.list.useQuery(undefined, { retry: false });

  // Sort: today first, then upcoming, then past
  const sorted = [...hearings].sort((a, b) => {
    if (a.hearingDate === today && b.hearingDate !== today) return -1;
    if (b.hearingDate === today && a.hearingDate !== today) return 1;
    return a.hearingDate.localeCompare(b.hearingDate);
  });

  return (
    <ClerkOSLayout>
      <div className="p-6 max-w-7xl mx-auto">
        <div className="mb-6 flex items-start justify-between gap-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-900 dark:text-slate-100">Hearings</h1>
            <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">
              Procedural timeline — all scheduled court events
            </p>
          </div>
          <div className="flex items-center gap-3">
            <div className="flex items-center gap-2 text-sm text-slate-500 dark:text-slate-400">
              <Gavel className="w-4 h-4" />
              <span>{hearings.length}</span>
            </div>
            <button
              onClick={() => setShowSchedule(true)}
              className="flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-lg bg-blue-600 text-white hover:bg-blue-700 transition-colors"
            >
              <Plus className="w-4 h-4" />
              Schedule
            </button>
          </div>
        </div>

        {error && (
          <div className="mb-4 flex items-center gap-3 p-4 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-xl">
            <AlertCircle className="w-5 h-5 text-amber-600 flex-shrink-0" />
            <p className="text-sm text-amber-700 dark:text-amber-300">
              Database not connected — no hearings to display.
            </p>
          </div>
        )}

        {/* Status filter */}
        <div className="flex gap-1 flex-wrap mb-5">
          {STATUSES.map((s) => (
            <button
              key={s}
              onClick={() => setStatus(s)}
              className={[
                'px-3 py-1.5 text-xs font-medium rounded-lg transition-colors',
                status === s
                  ? 'bg-blue-600 text-white'
                  : 'bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800',
              ].join(' ')}
            >
              {s}
            </button>
          ))}
        </div>

        {/* Table */}
        <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-slate-200 dark:border-slate-800">
                {['Date', 'Time', 'Courtroom', 'Judge', 'Status', 'Notes'].map((h) => (
                  <th
                    key={h}
                    className="px-4 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wide"
                  >
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {isLoading ? (
                Array.from({ length: 4 }).map((_, i) => (
                  <tr key={i}>
                    {Array.from({ length: 6 }).map((_, j) => (
                      <td key={j} className="px-4 py-3">
                        <div className="h-3.5 bg-slate-200 dark:bg-slate-800 rounded animate-pulse" />
                      </td>
                    ))}
                  </tr>
                ))
              ) : sorted.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-4 py-12 text-center text-slate-400 text-sm">
                    No hearings found
                  </td>
                </tr>
              ) : (
                sorted.map((h) => {
                  const isToday = h.hearingDate === today;
                  const isPast = h.hearingDate < today && h.status === 'scheduled';
                  return (
                    <tr
                      key={h.id}
                      className={[
                        'transition-colors',
                        isToday
                          ? 'bg-blue-50/50 dark:bg-blue-900/10'
                          : 'hover:bg-slate-50 dark:hover:bg-slate-800/50',
                      ].join(' ')}
                    >
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-2">
                          <span className={`font-medium ${isToday ? 'text-blue-700 dark:text-blue-400' : 'text-slate-900 dark:text-slate-100'}`}>
                            {new Date(h.hearingDate + 'T00:00:00').toLocaleDateString('en-GB', {
                              day: 'numeric',
                              month: 'short',
                              year: 'numeric',
                            })}
                          </span>
                          {isToday && (
                            <span className="text-[10px] font-bold px-1.5 py-0.5 rounded bg-blue-600 text-white">TODAY</span>
                          )}
                          {isPast && (
                            <span className="text-[10px] font-medium px-1.5 py-0.5 rounded bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400">OVERDUE</span>
                          )}
                        </div>
                      </td>
                      <td className="px-4 py-3 text-slate-600 dark:text-slate-400">{h.hearingTime}</td>
                      <td className="px-4 py-3 text-slate-900 dark:text-slate-100">{h.courtroom}</td>
                      <td className="px-4 py-3 text-slate-600 dark:text-slate-400 truncate max-w-[140px]">
                        {h.judge}
                      </td>
                      <td className="px-4 py-3">
                        <span className={`text-[10px] font-medium px-2 py-0.5 rounded-full ${STATUS_BADGE[h.status] ?? ''}`}>
                          {h.status}
                        </span>
                      </td>
                      <td className="px-4 py-3 text-slate-400 dark:text-slate-500 truncate max-w-[180px]">
                        {h.notes ?? '—'}
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      <ScheduleDialog open={showSchedule} onOpenChange={setShowSchedule} cases={cases} />
    </ClerkOSLayout>
  );
}

import { useState, FormEvent } from 'react';
import { useLocation } from 'wouter';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Loader2, CheckCircle, AlertCircle, ArrowLeft, AlertTriangle } from 'lucide-react';
import { toast } from 'sonner';

export default function IntakeSheet() {
  const [, setLocation] = useLocation();
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [matterRef, setMatterRef] = useState('');
  const [urgencyLevel, setUrgencyLevel] = useState('');
  const [error, setError] = useState('');

  const [formData, setFormData] = useState({
    clientName: '',
    clientEmail: '',
    clientPhone: '',
    matterType: '',
    urgency: '',
    description: '',
    claimValue: '',
  });

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const response = await fetch('/api/intake', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (response.ok && data.ok) {
        setSuccess(true);
        setMatterRef(data.matterRef);
        setUrgencyLevel(data.urgency);
        toast.success(data.message || 'Matter intake recorded successfully!');

        // Reset form
        setFormData({
          clientName: '',
          clientEmail: '',
          clientPhone: '',
          matterType: '',
          urgency: '',
          description: '',
          claimValue: '',
        });
      } else {
        setError(data.error || 'Failed to submit form. Please try again.');
        toast.error(data.error || 'Submission failed');
      }
    } catch (err) {
      console.error('Error submitting form:', err);
      setError('Network error. Please check your connection and try again.');
      toast.error('Network error occurred');
    } finally {
      setLoading(false);
    }
  };

  const getUrgencyColor = (urgency: string) => {
    switch (urgency.toLowerCase()) {
      case 'critical':
        return 'bg-red-500/20 border-red-500/50 text-red-400';
      case 'high':
        return 'bg-orange-500/20 border-orange-500/50 text-orange-400';
      case 'medium':
        return 'bg-yellow-500/20 border-yellow-500/50 text-yellow-400';
      case 'low':
        return 'bg-green-500/20 border-green-500/50 text-green-400';
      default:
        return 'bg-gray-500/20 border-gray-500/50 text-gray-400';
    }
  };

  if (success) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-[#0B0C10] via-[#1A1D28] to-[#0B0C10] flex items-center justify-center p-4">
        <Card className="w-full max-w-md bg-[#13151C] border-[#2A2D3A]">
          <CardHeader className="text-center">
            <div className="mx-auto mb-4 w-16 h-16 bg-cyan-500/20 rounded-full flex items-center justify-center">
              <CheckCircle className="w-8 h-8 text-cyan-400" />
            </div>
            <CardTitle className="text-2xl text-white">Intake Recorded!</CardTitle>
            <CardDescription className="text-gray-400">
              Your client matter has been successfully recorded
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4 text-center">
            <div className="p-4 bg-[#1A1D28] border border-[#2A2D3A] rounded-lg">
              <p className="text-sm text-gray-400 mb-2">Matter Reference</p>
              <p className="text-lg font-mono text-cyan-400 font-semibold">{matterRef}</p>
            </div>

            {urgencyLevel && (
              <div className={`p-3 rounded-lg border ${getUrgencyColor(urgencyLevel)}`}>
                <div className="flex items-center justify-center gap-2">
                  <AlertTriangle className="w-4 h-4" />
                  <span className="font-semibold">Priority: {urgencyLevel.toUpperCase()}</span>
                </div>
              </div>
            )}

            <p className="text-gray-300">
              Our team has been notified and will review this matter shortly.
            </p>

            <div className="flex gap-3">
              <Button
                onClick={() => setSuccess(false)}
                variant="outline"
                className="flex-1 bg-[#1A1D28] border-[#2A2D3A] hover:bg-[#252830] text-white"
              >
                Submit Another
              </Button>
              <Button
                onClick={() => setLocation('/ultai')}
                className="flex-1 bg-gradient-to-r from-cyan-500 to-blue-500 hover:from-cyan-600 hover:to-blue-600 text-white"
              >
                <ArrowLeft className="w-4 h-4 mr-2" />
                Back to UltAi
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#0B0C10] via-[#1A1D28] to-[#0B0C10] py-12 px-4">
      <div className="max-w-3xl mx-auto">
        <div className="mb-8 text-center">
          <h1 className="text-4xl font-bold text-white mb-4">Client Matter Intake Sheet</h1>
          <p className="text-gray-400 text-lg">
            Secure and confidential matter information collection
          </p>
        </div>

        <Card className="bg-[#13151C] border-[#2A2D3A]">
          <CardHeader>
            <CardTitle className="text-2xl text-white">New Matter Intake</CardTitle>
            <CardDescription className="text-gray-400">
              Please provide complete information about the client matter
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-6">
              {error && (
                <Alert variant="destructive" className="bg-red-500/10 border-red-500/50">
                  <AlertCircle className="h-4 w-4" />
                  <AlertDescription>{error}</AlertDescription>
                </Alert>
              )}

              {/* Client Information */}
              <div className="space-y-4">
                <h3 className="text-lg font-semibold text-white border-b border-[#2A2D3A] pb-2">
                  Client Information
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2 md:col-span-2">
                    <Label htmlFor="clientName" className="text-gray-300">
                      Client Name <span className="text-red-400">*</span>
                    </Label>
                    <Input
                      id="clientName"
                      required
                      value={formData.clientName}
                      onChange={(e) => setFormData({ ...formData, clientName: e.target.value })}
                      className="bg-[#1A1D28] border-[#2A2D3A] text-white focus:border-cyan-500"
                      placeholder="Full legal name"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="clientEmail" className="text-gray-300">
                      Client Email
                    </Label>
                    <Input
                      id="clientEmail"
                      type="email"
                      value={formData.clientEmail}
                      onChange={(e) => setFormData({ ...formData, clientEmail: e.target.value })}
                      className="bg-[#1A1D28] border-[#2A2D3A] text-white focus:border-cyan-500"
                      placeholder="client@example.com"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="clientPhone" className="text-gray-300">
                      Client Phone
                    </Label>
                    <Input
                      id="clientPhone"
                      type="tel"
                      value={formData.clientPhone}
                      onChange={(e) => setFormData({ ...formData, clientPhone: e.target.value })}
                      className="bg-[#1A1D28] border-[#2A2D3A] text-white focus:border-cyan-500"
                      placeholder="+1 (555) 123-4567"
                    />
                  </div>
                </div>
              </div>

              {/* Matter Details */}
              <div className="space-y-4">
                <h3 className="text-lg font-semibold text-white border-b border-[#2A2D3A] pb-2">
                  Matter Details
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <Label htmlFor="matterType" className="text-gray-300">
                      Matter Type <span className="text-red-400">*</span>
                    </Label>
                    <Select
                      value={formData.matterType}
                      onValueChange={(value) => setFormData({ ...formData, matterType: value })}
                      required
                    >
                      <SelectTrigger className="bg-[#1A1D28] border-[#2A2D3A] text-white">
                        <SelectValue placeholder="Select matter type" />
                      </SelectTrigger>
                      <SelectContent className="bg-[#1A1D28] border-[#2A2D3A]">
                        <SelectItem value="corporate">Corporate</SelectItem>
                        <SelectItem value="litigation">Litigation</SelectItem>
                        <SelectItem value="family">Family Law</SelectItem>
                        <SelectItem value="real-estate">Real Estate</SelectItem>
                        <SelectItem value="employment">Employment</SelectItem>
                        <SelectItem value="intellectual-property">Intellectual Property</SelectItem>
                        <SelectItem value="criminal">Criminal Defense</SelectItem>
                        <SelectItem value="immigration">Immigration</SelectItem>
                        <SelectItem value="other">Other</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="urgency" className="text-gray-300">
                      Urgency Level <span className="text-red-400">*</span>
                    </Label>
                    <Select
                      value={formData.urgency}
                      onValueChange={(value) => setFormData({ ...formData, urgency: value })}
                      required
                    >
                      <SelectTrigger className="bg-[#1A1D28] border-[#2A2D3A] text-white">
                        <SelectValue placeholder="Select urgency" />
                      </SelectTrigger>
                      <SelectContent className="bg-[#1A1D28] border-[#2A2D3A]">
                        <SelectItem value="critical">Critical (Immediate)</SelectItem>
                        <SelectItem value="high">High (Within 48 hours)</SelectItem>
                        <SelectItem value="medium">Medium (Within 1 week)</SelectItem>
                        <SelectItem value="low">Low (No rush)</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="claimValue" className="text-gray-300">
                      Estimated Claim Value
                    </Label>
                    <Input
                      id="claimValue"
                      value={formData.claimValue}
                      onChange={(e) => setFormData({ ...formData, claimValue: e.target.value })}
                      className="bg-[#1A1D28] border-[#2A2D3A] text-white focus:border-cyan-500"
                      placeholder="$50,000 - $100,000"
                    />
                  </div>
                </div>
              </div>

              {/* Matter Description */}
              <div className="space-y-2">
                <Label htmlFor="description" className="text-gray-300">
                  Matter Description
                </Label>
                <Textarea
                  id="description"
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  className="bg-[#1A1D28] border-[#2A2D3A] text-white focus:border-cyan-500 min-h-[150px]"
                  placeholder="Provide detailed information about the matter, key facts, timeline, and any other relevant details..."
                />
              </div>

              <div className="flex gap-3">
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => setLocation('/ultai')}
                  className="flex-1 bg-[#1A1D28] border-[#2A2D3A] hover:bg-[#252830] text-white"
                >
                  Cancel
                </Button>
                <Button
                  type="submit"
                  disabled={loading}
                  className="flex-1 bg-gradient-to-r from-cyan-500 to-blue-500 hover:from-cyan-600 hover:to-blue-600 text-white disabled:opacity-50"
                >
                  {loading ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      Submitting...
                    </>
                  ) : (
                    'Submit Intake'
                  )}
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>

        <p className="text-center text-gray-500 text-sm mt-6">
          All information is encrypted and handled with strict confidentiality
        </p>
      </div>
    </div>
  );
}

